import { useContext } from 'react';

import { _getTabIndexValue as getTabIndexValue } from '@dynatrace/strato-components/charts';

import { A11yToolbarTabIndexContext } from '../../../contexts/a11y-toolbar-tab-index.context.js';
import type {
  A11yToolbarTabIndex,
  ToolbarInteractionModes,
} from '../../../types/toolbar.js';
import { getTabIndexKey } from '../utils/a11y-toolbar-controls.js';

/**
 * Get tabIndex value from context. depending on the param type
 *
 * @param type - toolbar buttons type
 */
export const useA11yToolbarTabIndex = (type: ToolbarInteractionModes) => {
  const tabIndexContext = useContext<A11yToolbarTabIndex[]>(
    A11yToolbarTabIndexContext,
  );

  const toolbarTabIndex = tabIndexContext.find(
    (tab) => getTabIndexKey(tab) === type,
  );

  return toolbarTabIndex ? getTabIndexValue(toolbarTabIndex) : -1;
};
